/**
 * Handle chat prompt requests and proxy to Anthropic with server-side credentials.
 */
app.post("/api/chat", chatLimiter, async (req, res) => {
  const parsedBody = chatInputSchema.safeParse(req.body);
  if (!parsedBody.success) {
    res.status(400).json({
      error: "Invalid chat request payload",
      details: parsedBody.error.flatten(),
      requestId: req.requestId,
    });
    return;
  }

  const prompt = parsedBody.data.message || parsedBody.data.question;
  const requestHistory = parsedBody.data.history || [];

  if (!process.env.ANTHROPIC_API_KEY) {
    const localReply = buildLocalPortfolioReply(prompt);
    res.json({
      content: localReply,
      reply: localReply,
      model: "local-portfolio-fallback",
      fallback: true,
      requestId: req.requestId,
    });
    return;
  }

  try {
    const { content, model } = await sendAnthropicRequest(
      prompt,
      parsedBody.data.systemPrompt,
      req.requestId,
      requestHistory
    );
    res.json({
      content,
      reply: content,
      model,
      requestId: req.requestId,
    });
  } catch {
    const localReply = buildLocalPortfolioReply(prompt);
    res.json({
      content: localReply,
      reply: localReply,
      model: "local-portfolio-fallback",
      fallback: true,
      degraded: true,
      requestId: req.requestId,
    });
  }
});

/**
 * Handle contact form submissions and proxy to EmailJS from the server.
 */
app.post("/api/contact", contactLimiter, async (req, res) => {
  const parsedBody = contactInputSchema.safeParse(req.body);
  if (!parsedBody.success) {
    res.status(400).json({
      error: "Invalid contact request payload",
      details: parsedBody.error.flatten(),
      requestId: req.requestId,
    });
    return;
  }

  const serviceId = process.env.EMAILJS_SERVICE_ID;
  const templateId = process.env.EMAILJS_TEMPLATE_ID;
  const publicKey = process.env.EMAILJS_PUBLIC_KEY;

  if (!serviceId || !templateId || !publicKey) {
    res.status(503).json({
      error: "Contact service is not configured",
      requestId: req.requestId,
    });
    return;
  }

  try {
    const response = await fetch("https://api.emailjs.com/api/v1.0/email/send", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        service_id: serviceId,
        template_id: templateId,
        user_id: publicKey,
        template_params: {
          from_name: sanitizeText(parsedBody.data.name, 120),
          from_email: sanitizeText(parsedBody.data.email, 150),
          message: sanitizeText(parsedBody.data.message, 2000),
        },
      }),
    });

    if (!response.ok) {
      throw new Error(`EmailJS request failed: ${response.status}`);
    }

    res.json({
      status: "sent",
      requestId: req.requestId,
    });
  } catch {
    res.status(502).json({
      error: "Could not deliver message at this time",
      requestId: req.requestId,
    });
  }
});

