/**
 * Parse a comma-separated CORS origin string into an allowlist set.
 */
function parseCorsOrigins(originInput) {
  return new Set(
    (originInput || "http://127.0.0.1:5173,http://localhost:5173")
      .split(",")
      .map((origin) => origin.trim())
      .filter(Boolean)
  );
}

/**
 * Parse an integer env value and fallback if invalid or non-positive.
 */
function parsePositiveInteger(value, fallback) {
  const parsed = Number.parseInt(value || "", 10);
  if (Number.isNaN(parsed) || parsed <= 0) {
    return fallback;
  }

  return parsed;
}

/**
 * Check if a request origin is allowed by explicit list or Vercel previews.
 */
function isOriginAllowed(origin) {
  if (!origin) {
    return true;
  }

  if (corsOrigins.has(origin)) {
    return true;
  }

  return origin.endsWith(".vercel.app");
}

/**
 * Normalize user text inputs by reducing whitespace and max length.
 */
function sanitizeText(value, maxLength) {
  return String(value).replace(/\s+/g, " ").trim().slice(0, maxLength);
}

// Generated by GitHub Copilot
/**
 * Collect concise experience highlights matching query terms.
 *
 * @param {Array<{company?: string, role?: string, highlights?: string[]}>} entries Experience entries.
 * @param {string[]} terms Lowercase query terms to match.
 * @param {number} maxItems Maximum returned highlights.
 * @returns {string[]} Matched and formatted highlights.
 */
function collectExperienceHighlights(entries, terms, maxItems = 2) {
  const safeEntries = Array.isArray(entries) ? entries : [];
  const safeTerms = Array.isArray(terms) ? terms.filter(Boolean) : [];
  const results = [];

  for (const entry of safeEntries) {
    if (!entry || results.length >= maxItems) {
      continue;
    }

    const company = sanitizeText(entry.company || "", 120);
    const role = sanitizeText(entry.role || "", 120);
    const safeHighlights = Array.isArray(entry.highlights) ? entry.highlights : [];

    for (const rawHighlight of safeHighlights) {
      if (results.length >= maxItems) {
        break;
      }

      const highlight = sanitizeText(rawHighlight || "", 200);
      if (!highlight) {
        continue;
      }

      const searchableText = `${company} ${role} ${highlight}`.toLowerCase();
      const isMatch = safeTerms.some((term) => searchableText.includes(term));
      if (!isMatch) {
        continue;
      }

      results.push(`At ${company || "recent roles"}: ${highlight}`);
    }
  }

  return results;
}

